fn solve(chunks: Vec<String>, queries: Vec<String>) -> Vec<i64> {
    let s: String = chunks.into_iter().collect();
    let n = s.len();

    // Step 1: Identify all valid "words" in s and count their occurrences.
    // A word is a maximal contiguous sequence of characters satisfying:
    // 1. Composed of lowercase English letters ('a'-'z') or hyphens ('-').
    // 2. Hyphens must be surrounded by letters.
    let mut word_counts: HashMap<String, i64> = HashMap::new();

    let mut i = 0;
    while i < n {
        let start = i;

        // Skip separators (anything not a letter or a legal hyphen)
        while i < n && !s.chars().nth(i).unwrap_or(' ').is_ascii_alphanumeric() && s.chars().nth(i).unwrap_or(' ') != '-' {
            i += 1;
        }

        if i == n {
            break;
        }

        // Start of a potential word segment
        let mut j = i;
        while j < n {
            let char_j = s.chars().nth(j).unwrap();

            if char_j.is_ascii_alphabetic() {
                j += 1;
            } else if char_j == '-' {
                // Check if '-' is legal: must be surrounded by letters.
                // Check previous character (at j-1) and next character (at j+1).
                let prev_char_ok = j > 0 && s.chars().nth(j - 1).unwrap().is_ascii_alphabetic();
                let next_char_ok = j + 1 < n && s.chars().nth(j + 1).unwrap().is_ascii_alphabetic();

                if prev_char_ok && next_char_ok {
                    j += 1;
                } else {
                    // Illegal hyphen or boundary condition, stop segment here.
                    break;
                }
            } else {
                // Separator found, stop segment here.
                break;
            }
        }

        // The maximal segment is s[start..j] (if start < j)
        if start < j {
            let segment = &s[start..j];

            // Now, we must ensure this segment is a valid WORD (maximal in the sense of the definition).
            // The loop structure above ensures it's a maximal contiguous sequence of *allowed* chars
            // where '-' is legal. 
            // We need to confirm it's not just a part of a longer word defined by the rules.
            // The definition implies: "It is not some other word of greater length."

            // Since we are parsing maximal sequences based on separators, any sequence we extract here
            // should be a maximal candidate. We just need to check if the characters forming the segment
            // satisfy the composition rules strictly. The loop already enforces this for internal '-'s.

            // Let's re-evaluate the boundary condition for maximality.
            // A word starts after a separator (or start of s) and ends before a separator (or end of s).

            let mut is_valid_word = true;
            if segment.len() > 0 {
                for k in 0..segment.len() {
                    let char_k = segment.chars().nth(k).unwrap();
                    if !char_k.is_ascii_alphabetic() && char_k != '-' {
                        is_valid_word = false;
                        break;
                    }
                }

                // Check hyphen placement within the segment itself (this is partially redundant 
                // if the outer loop logic was perfect, but safer for the segment itself).
                for k in 1..segment.len() - 1 {
                    if segment.chars().nth(k).unwrap() == '-' {
                        let prev = segment.chars().nth(k - 1).unwrap();
                        let next = segment.chars().nth(k + 1).unwrap();
                        if !prev.is_ascii_alphabetic() || !next.is_ascii_alphabetic() {
                            is_valid_word = false;
                            break;
                        }
                    }
                }
            }

            if is_valid_word {
                // This segment is a maximal sequence composed of valid chars.
                // If it contains any characters that are not letters or validly placed hyphens,
                // it would have been broken up.
                *word_counts.entry(segment.to_string()).or_insert(0) += 1;
            }
        }

        // Move i to j to continue scanning from where the segment ended.
        i = j;
    }


